@startuml
class Account {
    label "I"
    method applyMonthlyChange()
}

class CreditAccount {
    label "C"
    attribute someAttribute
    method applyMonthlyInterest()
    method applyMonthlyChange()
    method ...someOtherMethod()
}

class DebitAccount {
    label "C"
    attribute someAttribute
    method applyMonthlyInterest()
    method deactivateIfUnderBalanced()
    method applyMonthlyChange()
    method ...someOtherMethod()
}

class PayrollAccount {
    label "C"
    attribute someAttribute
    method applyMonthlyChange()
    method ...someMethod()
}

class Bank {
    label "C"
    attribute accounts: [Account]
    method applyAllMonthlyChanges()
}

class Account {
    label "I"
    method applyMonthlyChange()
}

Account ..> CreditAccount
Account ..> DebitAccount
Account ..> PayrollAccount
Account ..> Bank

Bank ..> Account

note right of Account
applyAllMonthlyChanges()
{
  ...
  for every account a in accounts{
    a.applyMonthlyChange
  }
}
}

@enduml
